package com.wjx871.population.cancellation;
import com.wjx871.population.application.*;import com.wjx871.population.approval.*;import com.wjx871.population.audit.OperationLogService;import com.wjx871.population.common.BusinessException;import com.wjx871.population.material.*;import com.wjx871.population.migration.*;import com.wjx871.population.security.*;import jakarta.servlet.http.HttpServletRequest;import java.time.*;import java.util.*;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service @RequiredArgsConstructor public class CancellationService {
 private final CancellationMapper mapper;private final ApplicationService applications;private final BusinessApplicationMapper applicationMapper;private final CancellationMaterialRequirementService materialRules;private final ApplicationMaterialMapper materialMapper;private final ApprovalRequestMapper approvalRequests;private final ApprovalLogMapper logs;private final CancellationTransactionHook hook;private final OperationLogService audit;
 @Transactional public CancellationCreatedView createPerson(PersonCancellationRequest q,HttpServletRequest h){CancellationTarget t=requirePerson(q.personId());assertPersonActive(t);validatePersonReason(q.cancelReasonCode());if(mapper.countOpenPerson(q.personId(),null)>0)throw conflict("该人员已有未完成注销申请");validateHead(q.personId(),q.newHeadPersonId(),t);ApplicationView a=applications.createSpecialized(appReq(BusinessType.PERSON_CANCELLATION,q.title(),q.personId(),t.getHouseholdId(),q.reason(),q.remark(),null),h);CancellationRecord r=personRecord(a.applicationId(),q,t);mapper.insert(r);return created(a,r);}
 @Transactional public CancellationCreatedView createHousehold(HouseholdCancellationRequest q,HttpServletRequest h){CancellationTarget t=requireHousehold(q.householdId());validateHouseholdReason(q.cancelReasonCode());assertHouseholdEligible(t);if(mapper.countOpenHousehold(q.householdId(),null)>0)throw conflict("该家庭户已有未完成销户申请");ApplicationView a=applications.createSpecialized(appReq(BusinessType.HOUSEHOLD_CANCELLATION,q.title(),null,q.householdId(),q.reason(),q.remark(),null),h);CancellationRecord r=householdRecord(a.applicationId(),q);mapper.insert(r);return created(a,r);}
 @Transactional public CancellationCreatedView updatePerson(Long id,PersonCancellationRequest q){BusinessApplication a=requireOwnedDraft(id);CancellationRecord old=requireRecord(id,CancelObjectType.PERSON);if(q.version()==null)throw bad("version 不能为空");if(!old.getPersonId().equals(q.personId()))throw bad("注销对象不能修改");CancellationTarget t=requirePerson(q.personId());assertPersonActive(t);validatePersonReason(q.cancelReasonCode());validateHead(q.personId(),q.newHeadPersonId(),t);CancellationRecord r=personRecord(id,q,t);if(mapper.updateDraft(r,q.version())==0)ApplicationService.conflict();ApplicationView av=applications.updateSpecialized(id,appReq(BusinessType.PERSON_CANCELLATION,q.title(),q.personId(),t.getHouseholdId(),q.reason(),q.remark(),a.getVersion()));return new CancellationCreatedView(id,av.applicationNo(),old.getCancellationId(),old.getCancellationNo(),av.status(),CancellationStatus.DRAFT);}
 @Transactional public CancellationCreatedView updateHousehold(Long id,HouseholdCancellationRequest q){BusinessApplication a=requireOwnedDraft(id);CancellationRecord old=requireRecord(id,CancelObjectType.HOUSEHOLD);if(q.version()==null)throw bad("version 不能为空");if(!old.getHouseholdId().equals(q.householdId()))throw bad("注销对象不能修改");CancellationTarget t=requireHousehold(q.householdId());assertHouseholdEligible(t);validateHouseholdReason(q.cancelReasonCode());CancellationRecord r=householdRecord(id,q);if(mapper.updateDraft(r,q.version())==0)ApplicationService.conflict();ApplicationView av=applications.updateSpecialized(id,appReq(BusinessType.HOUSEHOLD_CANCELLATION,q.title(),null,q.householdId(),q.reason(),q.remark(),a.getVersion()));return new CancellationCreatedView(id,av.applicationNo(),old.getCancellationId(),old.getCancellationNo(),av.status(),CancellationStatus.DRAFT);}
 @Transactional(readOnly=true) public CancellationDetailView detail(Long id){BusinessApplication a=applications.require(id);assertScope(a,CurrentUserContext.requireUser());CancellationRecord r=mapper.findByApplication(id).orElseThrow(()->notFound("注销详情不存在"));CancellationTarget t=r.getCancelObjectType()==CancelObjectType.PERSON?requirePerson(r.getPersonId()):requireHousehold(r.getHouseholdId());Residence res=r.getPersonId()==null?null:mapper.findResidence(r.getPersonId()).orElse(null);boolean executable=a.getStatus()==ApplicationStatus.APPROVED&&r.getBusinessStatus()==CancellationStatus.APPROVED;boolean full=canFull(CurrentUserContext.requireUser());return new CancellationDetailView(ApplicationView.from(a),CancellationView.from(r,full),t,res,t.getHouseholdId()==null?List.of():mapper.activeMembers(t.getHouseholdId()),materialMapper.selectByApplicationId(id).stream().map(MaterialView::from).toList(),approvalRequests.selectByApplicationId(id).orElse(null),logs.selectByApplicationId(id).stream().map(ApprovalLogView::from).toList(),mapper.findResidenceArchive(id).orElse(null),mapper.findHouseholdArchiveByApplication(id).orElse(null),executable,executable?null:"申请尚未批准或已执行");}
 @Transactional public void executePerson(Long id,ExecuteRequest q,HttpServletRequest h){AuthenticatedUser u=CurrentUserContext.requireUser();BusinessApplication a=applications.require(id);assertExecute(a,u);CancellationRecord r=mapper.lockByApplication(id).orElseThrow(()->notFound("注销详情不存在"));requireApproved(a,r,CancelObjectType.PERSON,q.version());CancellationTarget t=mapper.lockPersonTarget(r.getPersonId()).orElseThrow(()->notFound("人员不存在"));assertPersonActive(t);validateHead(r.getPersonId(),r.getNewHeadPersonId(),t);materialRules.verified(id);Residence residence=mapper.lockResidence(r.getPersonId()).orElse(null);if(residence!=null){String type=isDeath(r.getCancelReasonCode())?"DEATH_CANCELLATION":"PERSON_CANCELLATION";if(mapper.insertResidenceArchive(r,residence,u.userId(),type)==0)throw conflict("户籍归档失败");hook.afterResidenceArchive();if(mapper.deleteResidence(residence.getResidenceId(),residence.getVersion())==0)ApplicationService.conflict();hook.afterResidenceDelete();}if(t.getHouseholdId()!=null){if(mapper.cancelMember(t.getHouseholdId(),r.getPersonId(),r.getEventDate())==0)throw conflict("当前家庭成员关系无效");hook.afterMemberUpdate();if(r.getPersonId().equals(t.getHeadPersonId())){if(t.getActiveMemberCount()>1){if(mapper.changeHead(t.getHouseholdId(),r.getPersonId(),r.getNewHeadPersonId())==0)ApplicationService.conflict();}else if(mapper.markPending(t.getHouseholdId(),r.getPersonId())==0)ApplicationService.conflict();}}if(mapper.updatePersonStatus(r.getPersonId(),isDeath(r.getCancelReasonCode())?"DECEASED":"CANCELLED")==0)throw conflict("人员已被注销");hook.afterPersonUpdate();mapper.fillSnapshot(id,t);complete(a,r,u.userId());executionLog(a,u,h,"PERSON_CANCELLATION_EXECUTE");}
 @Transactional public void executeHousehold(Long id,ExecuteRequest q,HttpServletRequest h){AuthenticatedUser u=CurrentUserContext.requireUser();BusinessApplication a=applications.require(id);assertExecute(a,u);CancellationRecord r=mapper.lockByApplication(id).orElseThrow(()->notFound("注销详情不存在"));requireApproved(a,r,CancelObjectType.HOUSEHOLD,q.version());CancellationTarget t=mapper.lockHouseholdTarget(r.getHouseholdId()).orElseThrow(()->notFound("家庭户不存在"));assertHouseholdEligible(t);materialRules.verified(id);if(mapper.insertHouseholdArchive(r,t,u.userId())==0)throw conflict("家庭户归档失败");hook.afterHouseholdArchive();if(mapper.cancelHousehold(r.getHouseholdId())==0)ApplicationService.conflict();hook.afterHouseholdUpdate();mapper.fillSnapshot(id,t);complete(a,r,u.userId());executionLog(a,u,h,"HOUSEHOLD_CANCELLATION_EXECUTE");}
 @Transactional(readOnly=true) public Page<CancellationView> search(String no,String object,String reason,String person,String identity,String household,String status,String region,LocalDate from,LocalDate to,Pageable p){AuthenticatedUser u=CurrentUserContext.requireUser();String scoped=scopeRegion(u,region);boolean full=canFull(u);return new PageImpl<>(mapper.search(trim(no),trim(object),trim(reason),trim(person),trim(identity),trim(household),trim(status),scoped,from,to,p.getPageSize(),p.getOffset()).stream().map(r->CancellationView.from(r,full)).toList(),p,mapper.count(trim(no),trim(object),trim(reason),trim(person),trim(identity),trim(household),trim(status),scoped,from,to));}
 @Transactional(readOnly=true) public Page<HouseholdArchive> archives(String household,String head,String region,String reason,LocalDateTime from,LocalDateTime to,Pageable p){String scoped=scopeRegion(CurrentUserContext.requireUser(),region);return new PageImpl<>(mapper.searchHouseholdArchives(trim(household),trim(head),scoped,trim(reason),from,to,p.getPageSize(),p.getOffset()),p,mapper.countHouseholdArchives(trim(household),trim(head),scoped,trim(reason),from,to));}
 @Transactional(readOnly=true) public HouseholdArchive archive(Long id){HouseholdArchive a=mapper.findHouseholdArchive(id).orElseThrow(()->notFound("家庭户归档不存在"));assertRegion(a.getRegionCodeSnapshot(),CurrentUserContext.requireUser());return a;}
 private void complete(BusinessApplication a,CancellationRecord r,Long user){if(mapper.updateStatus(a.getApplicationId(),CancellationStatus.APPROVED,CancellationStatus.COMPLETED,r.getVersion(),user)==0)ApplicationService.conflict();if(applicationMapper.updateStatus(a.getApplicationId(),ApplicationStatus.APPROVED,ApplicationStatus.COMPLETED,a.getVersion())==0)ApplicationService.conflict();}
 private void executionLog(BusinessApplication a,AuthenticatedUser u,HttpServletRequest h,String type){logs.insert(ApprovalLog.of(null,a.getApplicationId(),ApprovalAction.EXECUTE,ApplicationStatus.APPROVED.name(),ApplicationStatus.COMPLETED.name(),u.userId(),"注销业务执行完成",audit.clientIp(h)));audit.recordTransactional(u.userId(),type,h);}
 private void requireApproved(BusinessApplication a,CancellationRecord r,CancelObjectType type,int version){if(a.getStatus()!=ApplicationStatus.APPROVED||r.getBusinessStatus()!=CancellationStatus.APPROVED||r.getCancelObjectType()!=type)throw conflict("申请尚未批准或已执行");if(r.getVersion()!=version)ApplicationService.conflict();}
 private BusinessApplication requireOwnedDraft(Long id){BusinessApplication a=applications.require(id);applications.assertOwner(a,CurrentUserContext.requireUser());if(a.getStatus()!=ApplicationStatus.DRAFT)throw conflict("只有草稿可修改");return a;}
 private CancellationRecord requireRecord(Long id,CancelObjectType type){CancellationRecord r=mapper.findByApplication(id).orElseThrow(()->notFound("注销详情不存在"));if(r.getCancelObjectType()!=type)throw bad("注销对象类型错误");return r;}
 private CancellationTarget requirePerson(Long id){return mapper.findPersonTarget(id).orElseThrow(()->notFound("人员不存在"));}private CancellationTarget requireHousehold(Long id){return mapper.findHouseholdTarget(id).orElseThrow(()->notFound("家庭户不存在"));}
 private void assertPersonActive(CancellationTarget t){if("CANCELLED".equals(t.getCurrentStatusCode())||"DECEASED".equals(t.getCurrentStatusCode()))throw conflict("人员已经注销");}
 private void assertHouseholdEligible(CancellationTarget t){if(!"PENDING_CANCELLATION".equals(t.getHouseholdStatus())||t.getActiveMemberCount()>0||t.getResidenceCount()>0||mapper.countPendingMigrationIn(t.getHouseholdId())>0)throw conflict("家庭户不满足销户条件");}
 private void validateHead(Long person,Long newHead,CancellationTarget t){if(t.getHouseholdId()!=null&&person.equals(t.getHeadPersonId())&&t.getActiveMemberCount()>1&&(newHead==null||newHead.equals(person)||!mapper.activeMembers(t.getHouseholdId()).contains(newHead)))throw conflict("户主注销且仍有其他成员时必须指定有效新户主");}
 private void validatePersonReason(CancelReasonCode r){if(EnumSet.of(CancelReasonCode.NO_ACTIVE_MEMBERS,CancelReasonCode.HOUSEHOLD_MERGED,CancelReasonCode.ADDRESS_INVALIDATED).contains(r))throw bad("无效人员注销原因");}private void validateHouseholdReason(CancelReasonCode r){if(!EnumSet.of(CancelReasonCode.NO_ACTIVE_MEMBERS,CancelReasonCode.HOUSEHOLD_MERGED,CancelReasonCode.ADDRESS_INVALIDATED,CancelReasonCode.OTHER_APPROVED).contains(r))throw bad("无效家庭户注销原因");}
 private boolean isDeath(CancelReasonCode r){return r==CancelReasonCode.DEATH||r==CancelReasonCode.DECLARED_DEAD;}private void assertExecute(BusinessApplication a,AuthenticatedUser u){if(!u.permissions().contains("cancellation:execute"))throw new BusinessException(HttpStatus.FORBIDDEN,"无注销执行权限");assertScope(a,u);}private void assertScope(BusinessApplication a,AuthenticatedUser u){if(a.getApplicantUserId().equals(u.userId())||u.dataScope()==DataScope.ALL)return;if(u.dataScope()==DataScope.DEPARTMENT&&Objects.equals(a.getApplicantDepartmentId(),u.departmentId()))return;if(u.dataScope()==DataScope.REGION&&includesRegion(u.regionCode(),a.getApplicantRegionCode()))return;throw new BusinessException(HttpStatus.FORBIDDEN,"超出注销数据范围");}
 private String scopeRegion(AuthenticatedUser u,String requested){if(u.dataScope()==DataScope.ALL)return trim(requested);if(u.dataScope()==DataScope.SELF)throw new BusinessException(HttpStatus.FORBIDDEN,"SELF 范围不能查询注销归档");if(requested!=null&&!sameRegion(requested,u.regionCode()))throw new BusinessException(HttpStatus.FORBIDDEN,"超出数据范围");return u.regionCode();}private void assertRegion(String r,AuthenticatedUser u){if(u.dataScope()!=DataScope.ALL&&!sameRegion(r,u.regionCode()))throw new BusinessException(HttpStatus.FORBIDDEN,"超出数据范围");}private boolean sameRegion(String a,String b){return a!=null&&b!=null&&a.length()>1&&b.length()>1&&a.substring(0,2).equals(b.substring(0,2));}private boolean includesRegion(String scope,String target){if(scope==null||target==null)return false;String prefix=scope.replaceFirst("0+$","");return !prefix.isBlank()&&target.startsWith(prefix);}private boolean canFull(AuthenticatedUser u){return u.permissions().contains("cancellation:execute")||u.permissions().contains("system:user:manage");}
 private CancellationRecord personRecord(Long id,PersonCancellationRequest q,CancellationTarget t){CancellationRecord r=new CancellationRecord();r.setCancellationNo(ApplicationService.generateNumber("CNL"));r.setApplicationId(id);r.setCancelObjectType(CancelObjectType.PERSON);r.setPersonId(q.personId());r.setSourceHouseholdId(t.getHouseholdId());r.setCancelReasonCode(q.cancelReasonCode());r.setCancelReasonDetail(q.cancelReasonDetail());r.setEventDate(q.eventDate());r.setNewHeadPersonId(q.newHeadPersonId());r.setBusinessStatus(CancellationStatus.DRAFT);r.setVersion(0);return r;}private CancellationRecord householdRecord(Long id,HouseholdCancellationRequest q){CancellationRecord r=new CancellationRecord();r.setCancellationNo(ApplicationService.generateNumber("CNL"));r.setApplicationId(id);r.setCancelObjectType(CancelObjectType.HOUSEHOLD);r.setHouseholdId(q.householdId());r.setCancelReasonCode(q.cancelReasonCode());r.setCancelReasonDetail(q.cancelReasonDetail());r.setEventDate(q.eventDate());r.setBusinessStatus(CancellationStatus.DRAFT);r.setVersion(0);return r;}
 private CancellationCreatedView created(ApplicationView a,CancellationRecord r){return new CancellationCreatedView(a.applicationId(),a.applicationNo(),r.getCancellationId(),r.getCancellationNo(),a.status(),r.getBusinessStatus());}private ApplicationRequest appReq(BusinessType t,String title,Long p,Long hh,String reason,String remark,Integer v){return new ApplicationRequest(t,title,p,hh,reason,remark,v);}private String trim(String s){return s==null||s.isBlank()?null:s.trim();}private BusinessException conflict(String m){return new BusinessException(HttpStatus.CONFLICT,m);}private BusinessException bad(String m){return new BusinessException(HttpStatus.BAD_REQUEST,m);}private BusinessException notFound(String m){return new BusinessException(HttpStatus.NOT_FOUND,m);}
}
